import { useState, useEffect, useCallback } from "react";
import { Settings, X, Delete, Info } from "lucide-react";

const SUN_IMG = "data:image/webp;base64,";
const MOON_IMG = "data:image/png;base64,";
const MOON2_IMG = "data:image/png;base64,";

const ROWS = 6;
const COLS = 5;

async function fetchRandomWord() {
  try {
    const res = await fetch("https://random-word-api.herokuapp.com/word?length=5");
    const data = await res.json();
    const word = data[0]?.toUpperCase();
    if (word && word.length === COLS && /^[A-Z]+$/.test(word)) {
      // Confirm it's a real dictionary word too
      const check = await fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${word.toLowerCase()}`);
      if (check.ok) return word;
    }
    throw new Error("invalid word from API");
  } catch (err) {
    // Fallback list in case the API is down or returns something unusable
    const FALLBACK = [
      "APPLE", "BRAVE", "CRANE", "DREAM", "EAGLE", "FLAME", "GHOST", "HEART",
      "IVORY", "JOKER", "KNIFE", "LEMON", "MANGO", "NOBLE", "OCEAN", "PEACH",
    ];
    return FALLBACK[Math.floor(Math.random() * FALLBACK.length)];
  }
}

function getStatuses(guess, answer) {
  const result = Array(COLS).fill("absent");
  const answerArr = answer.split("");
  const used = Array(COLS).fill(false);

  for (let i = 0; i < COLS; i++) {
    if (guess[i] === answerArr[i]) {
      result[i] = "correct";
      used[i] = true;
    }
  }
  for (let i = 0; i < COLS; i++) {
    if (result[i] === "correct") continue;
    const idx = answerArr.findIndex((l, j) => l === guess[i] && !used[j]);
    if (idx !== -1) {
      result[i] = "present";
      used[idx] = true;
    }
  }
  return result;
}

export default function Wordle() {
  const [answer, setAnswer] = useState("");
  const [loadingWord, setLoadingWord] = useState(true);
  const [guesses, setGuesses] = useState([]);
  const [statuses, setStatuses] = useState([]);
  const [current, setCurrent] = useState("");
  const [gameState, setGameState] = useState("playing"); // playing | won | lost
  const [shakeRow, setShakeRow] = useState(-1);
  const [message, setMessage] = useState("");
  const [darkMode, setDarkMode] = useState(false);
  const [colorBlind, setColorBlind] = useState(false);
  const [hardMode, setHardMode] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [letterStatus, setLetterStatus] = useState({});

  const flashMessage = (msg) => {
    setMessage(msg);
    setTimeout(() => setMessage(""), 1500);
  };

  const newGame = useCallback(async () => {
    setLoadingWord(true);
    const word = await fetchRandomWord();
    setAnswer(word);
    setGuesses([]);
    setStatuses([]);
    setCurrent("");
    setGameState("playing");
    setLetterStatus({});
    setMessage("");
    setLoadingWord(false);
  }, []);

  useEffect(() => {
    newGame();
  }, []);

  const [isChecking, setIsChecking] = useState(false);

  const isRealWord = async (word) => {
    try {
      const res = await fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${word.toLowerCase()}`);
      return res.ok;
    } catch (err) {
      // If the API is unreachable, don't block the player — allow the guess
      return true;
    }
  };

  const submitGuess = useCallback(async () => {
    if (current.length !== COLS) {
      setShakeRow(guesses.length);
      setTimeout(() => setShakeRow(-1), 400);
      flashMessage("Not enough letters");
      return;
    }

    setIsChecking(true);
    const valid = await isRealWord(current);
    setIsChecking(false);

    if (!valid) {
      setShakeRow(guesses.length);
      setTimeout(() => setShakeRow(-1), 400);
      flashMessage("Not in word list");
      return;
    }

    // Hard mode check: any letter marked present/correct in a previous guess must reappear
    if (hardMode) {
      // Check required positions (green) must stay in same place
      for (let r = 0; r < guesses.length; r++) {
        for (let i = 0; i < COLS; i++) {
          if (statuses[r][i] === "correct" && current[i] !== guesses[r][i]) {
            setShakeRow(guesses.length);
            setTimeout(() => setShakeRow(-1), 400);
            flashMessage(`Letter ${guesses[r][i]} must be in position ${i + 1}`);
            return;
          }
        }
      }
      // Check yellow letters must be used somewhere in the guess
      const mustInclude = new Set();
      for (let r = 0; r < guesses.length; r++) {
        for (let i = 0; i < COLS; i++) {
          if (statuses[r][i] === "present") mustInclude.add(guesses[r][i]);
        }
      }
      for (const letter of mustInclude) {
        if (!current.includes(letter)) {
          setShakeRow(guesses.length);
          setTimeout(() => setShakeRow(-1), 400);
          flashMessage(`Must use letter ${letter}`);
          return;
        }
      }
    }

    const result = getStatuses(current, answer);
    const newGuesses = [...guesses, current];
    const newStatuses = [...statuses, result];
    setGuesses(newGuesses);
    setStatuses(newStatuses);

    setLetterStatus((prev) => {
      const next = { ...prev };
      current.split("").forEach((letter, i) => {
        const rank = { absent: 0, present: 1, correct: 2 };
        if (!next[letter] || rank[result[i]] > rank[next[letter]]) {
          next[letter] = result[i];
        }
      });
      return next;
    });

    if (current === answer) {
      setGameState("won");
    } else if (newGuesses.length === ROWS) {
      setGameState("lost");
    }
    setCurrent("");
  }, [current, guesses, statuses, answer, hardMode, letterStatus]);

  const handleKey = useCallback(
    (key) => {
      if (gameState !== "playing") return;
      if (key === "ENTER") {
        submitGuess();
      } else if (key === "BACKSPACE") {
        setCurrent((c) => c.slice(0, -1));
      } else if (/^[A-Z]$/.test(key) && current.length < COLS) {
        setCurrent((c) => c + key);
      }
    },
    [current, gameState, submitGuess]
  );

  useEffect(() => {
    const onKeyDown = (e) => {
      if (showSettings || showHelp) return;
      let key = e.key.toUpperCase();
      if (key === "BACKSPACE" || key === "ENTER" || /^[A-Z]$/.test(key)) {
        handleKey(key);
      }
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [handleKey, showSettings, showHelp]);

  // Color tokens depending on mode
  const colors = colorBlind
    ? { correct: "bg-orange-500 border-orange-500", present: "bg-blue-500 border-blue-500", absent: darkMode ? "bg-gray-700 border-gray-700" : "bg-gray-400 border-gray-400" }
    : { correct: "bg-green-600 border-green-600", present: "bg-yellow-500 border-yellow-500", absent: darkMode ? "bg-gray-700 border-gray-700" : "bg-gray-400 border-gray-400" };

  const bg = darkMode ? "bg-zinc-900" : "bg-white";
  const text = darkMode ? "text-zinc-100" : "text-zinc-900";
  const border = darkMode ? "border-zinc-600" : "border-zinc-300";
  const panelBg = darkMode ? "bg-zinc-800" : "bg-zinc-100";

  const keyRows = [
    "QWERTYUIOP".split(""),
    "ASDFGHJKL".split(""),
    ["ENTER", ..."ZXCVBNM".split(""), "BACKSPACE"],
  ];

  const keyColorClass = (key) => {
    const status = letterStatus[key];
    if (!status) return darkMode ? "bg-zinc-600 text-white" : "bg-zinc-300 text-zinc-900";
    if (status === "correct") return `${colors.correct} text-white`;
    if (status === "present") return `${colors.present} text-white`;
    return darkMode ? "bg-zinc-800 text-zinc-400" : "bg-zinc-400 text-white";
  };

  return (
    <div className={`relative h-screen max-h-screen w-full flex flex-col items-center ${bg} ${text} font-sans py-2 px-1 sm:px-2 transition-colors duration-300 overflow-hidden`}>
      {gameState === "won" && <Confetti />}
      {darkMode ? (
        <img
          src={MOON2_IMG}
          alt=""
          aria-hidden="true"
          className="pointer-events-none select-none absolute right-0 top-1/2 -translate-y-1/2 w-32 sm:w-48 md:w-60 opacity-95 z-0"
        />
      ) : (
        <img
          src={SUN_IMG}
          alt=""
          aria-hidden="true"
          className="pointer-events-none select-none absolute right-0 top-1/2 -translate-y-1/2 w-32 sm:w-48 md:w-60 opacity-95 z-0"
        />
      )}
      <div
        className={`pointer-events-none select-none absolute right-28 sm:right-40 md:right-52 top-[25%] sm:top-[25%] max-w-[160px] sm:max-w-[200px] rounded-3xl px-3 py-2 sm:px-4 sm:py-3 text-sm sm:text-base font-semibold text-center shadow-md ${darkMode ? "bg-indigo-200 text-indigo-950" : "bg-yellow-400 text-black"}`}
        style={{ fontFamily: "'Baloo 2', system-ui, sans-serif" }}
      >
        Hey there! Ready to crack today's word?
        <span className={`absolute -bottom-1.5 right-3 w-3 h-3 rotate-45 ${darkMode ? "bg-indigo-200" : "bg-yellow-400"}`} />
        <span className={`absolute -bottom-4 right-0 w-2 h-2 rounded-full ${darkMode ? "bg-indigo-200" : "bg-yellow-400"}`} />
        <span className={`absolute -bottom-6 right-[-6px] w-1.5 h-1.5 rounded-full ${darkMode ? "bg-indigo-200" : "bg-yellow-400"}`} />
      </div>
      <div className="absolute top-3 left-3 sm:top-4 sm:left-25 z-20">
        <BubbleTitle darkMode={darkMode} colorBlind={colorBlind} />
      </div>
      <div className="absolute top-3 right-3 sm:top-4 sm:right-4 z-20 flex items-center gap-3">
        <button
          onClick={() => setShowHelp(true)}
          className={`p-2 rounded-full hover:bg-opacity-10 hover:bg-gray-500 transition`}
          aria-label="How to play"
        >
          <Info size={28} />
        </button>
        <button
          onClick={() => setShowSettings(true)}
          className="p-2 rounded-full hover:bg-opacity-10 hover:bg-gray-500 transition"
          aria-label="Settings"
        >
          <Settings size={28} />
        </button>
      </div>
      <div className="relative z-10 w-full flex-1 flex flex-col items-center justify-center pt-14 sm:pt-16 overflow-hidden">
      {/* Message toast */}
      <div className="h-6 mb-1">
        {message && (
          <div className={`px-4 py-1 rounded font-semibold text-sm ${darkMode ? "bg-zinc-100 text-zinc-900" : "bg-zinc-900 text-white"}`}>
            {message}
          </div>
        )}
      </div>

      {/* Hard mode badge */}
      {hardMode && (
        <div className="mb-1 text-xs uppercase tracking-wider px-2 py-0.5 rounded bg-red-600 text-white font-bold">
          Hard Mode
        </div>
      )}

      {loadingWord ? (
        <div className="flex-1 flex items-center justify-center py-20 text-sm opacity-70">
          Fetching today's word…
        </div>
      ) : (
      <>
      {/* Result banner */}
      {gameState !== "playing" && (
        <div
          className={`mb-3 px-5 py-2 rounded-lg font-extrabold text-center shadow-md ${
            gameState === "won" ? "bg-green-600 text-white" : "bg-red-600 text-white"
          }`}
        >
          <div className="text-xl sm:text-2xl tracking-wide">
            {gameState === "won" ? "YOU WON!" : "YOU LOST"}
          </div>
          {gameState === "lost" && (
            <div className="text-sm sm:text-base font-semibold mt-1 tracking-widest">
              The word was: {answer.toUpperCase()}
            </div>
          )}
        </div>
      )}
      {/* Board */}
      <div className="grid grid-rows-6 gap-1.5 sm:gap-2 mb-3">
        {Array.from({ length: ROWS }).map((_, r) => {
          const isCurrentRow = r === guesses.length;
          const word = isCurrentRow ? current : guesses[r] || "";
          const rowStatuses = statuses[r];
          return (
            <div
              key={r}
              className={`grid grid-cols-5 gap-1.5 sm:gap-2 ${shakeRow === r ? "animate-pulse" : ""}`}
            >
              {Array.from({ length: COLS }).map((_, c) => {
                const letter = word[c] || "";
                const status = rowStatuses ? rowStatuses[c] : null;
                let cellClass = "border-yellow-400 " + bg;
                if (status) {
                  cellClass = `${colors[status]} text-white`;
                } else if (letter) {
                  cellClass = "border-yellow-400 " + bg + " border-2";
                }
                return (
                  <div
                    key={c}
                    className={`w-9 h-9 xs:w-10 xs:h-10 sm:w-12 sm:h-12 border-2 flex items-center justify-center text-lg sm:text-xl font-bold uppercase rounded ${cellClass} transition-colors duration-300`}
                  >
                    {colorBlind && status === "correct" && letter}
                    {letter}
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>

      {/* Keyboard */}
      <div className="w-full max-w-md flex flex-col gap-1 sm:gap-1.5 px-1">
        {keyRows.map((row, i) => (
          <div key={i} className="flex justify-center gap-1">
            {row.map((key) => (
              <button
                key={key}
                onClick={() => handleKey(key)}
                className={`flex items-center justify-center rounded font-bold text-[10px] sm:text-sm h-9 sm:h-10 ${
                  key === "ENTER" || key === "BACKSPACE" ? "px-1.5 sm:px-2 min-w-[36px] sm:min-w-[48px]" : "flex-1 min-w-[22px] sm:min-w-[28px]"
                } ${keyColorClass(key)} active:scale-95 transition`}
              >
                {key === "BACKSPACE" ? <Delete size={16} /> : key === "ENTER" ? "ENTER" : key}
              </button>
            ))}
          </div>
        ))}
      </div>

      </>
      )}

      {gameState !== "playing" && (
        <button
          onClick={newGame}
          className={`mt-6 px-5 py-2 rounded font-semibold ${darkMode ? "bg-zinc-100 text-zinc-900" : "bg-zinc-900 text-white"} hover:opacity-90 transition`}
        >
          Play Again
        </button>
      )}

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4" onClick={() => setShowSettings(false)}>
          <div className={`${panelBg} ${text} rounded-lg p-5 w-full max-w-sm`} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-bold">Settings</h2>
              <button onClick={() => setShowSettings(false)}><X size={20} /></button>
            </div>

            <div className="flex items-center justify-between py-3 border-b border-zinc-500/30">
              <div>
                <p className="font-semibold">Dark Mode</p>
              </div>
              <Toggle checked={darkMode} onChange={() => setDarkMode((d) => !d)} />
            </div>

            <div className="flex items-center justify-between py-3 border-b border-zinc-500/30">
              <div>
                <p className="font-semibold">Hard Mode</p>
                <p className="text-xs opacity-70">Revealed hints must be used in later guesses</p>
              </div>
              <Toggle
                checked={hardMode}
                onChange={() => {
                  if (guesses.length === 0) setHardMode((h) => !h);
                  else flashMessage("Can only toggle before first guess");
                }}
              />
            </div>

            <div className="flex items-center justify-between py-3">
              <div>
                <p className="font-semibold">Colorblind Mode</p>
                <p className="text-xs opacity-70">Uses orange/blue instead of green/yellow</p>
              </div>
              <Toggle checked={colorBlind} onChange={() => setColorBlind((c) => !c)} />
            </div>

            <button
              onClick={() => {
                newGame();
                setShowSettings(false);
              }}
              className="mt-4 w-full py-2 rounded font-semibold bg-red-600 text-white hover:bg-red-700 transition"
            >
              New Game
            </button>
          </div>
        </div>
      )}

      {/* Help Modal */}
      {showHelp && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4" onClick={() => setShowHelp(false)}>
          <div className={`${panelBg} ${text} rounded-lg p-5 w-full max-w-sm`} onClick={(e) => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-bold">How to Play</h2>
              <button onClick={() => setShowHelp(false)}><X size={20} /></button>
            </div>
            <p className="text-sm mb-3">Guess the 5-letter word in 6 tries. After each guess, tile colors show how close you were.</p>

            <div className="flex gap-1 mb-2">
              <div className={`w-9 h-9 ${colors.correct} text-white flex items-center justify-center font-bold rounded`}>A</div>
              <p className="text-sm self-center">Letter is correct and in the right spot{colorBlind ? "" : " (green)"}.</p>
            </div>
            <div className="flex gap-1 mb-2">
              <div className={`w-9 h-9 ${colors.present} text-white flex items-center justify-center font-bold rounded relative`}>
                B
              </div>
              <p className="text-sm self-center">Letter is in the word but wrong spot{colorBlind ? "" : " (yellow)"}.</p>
            </div>
            <div className="flex gap-1 mb-3">
              <div className={`w-9 h-9 ${colors.absent} text-white flex items-center justify-center font-bold rounded`}>C</div>
              <p className="text-sm self-center">Letter is not in the word.</p>
            </div>
            <p className="text-xs opacity-70">Tip: turn on Colorblind Mode in Settings for orange/blue tiles instead of green/yellow.</p>
          </div>
        </div>
      )}
      </div>
    </div>
  );
}

function Confetti() {
  const colors = ["#22c55e", "#eab308", "#ff8a3d", "#3d8bff", "#ef4444", "#a855f7"];
  const pieces = Array.from({ length: 80 }, (_, i) => ({
    id: i,
    left: Math.random() * 100,
    delay: Math.random() * 0.6,
    duration: 2.2 + Math.random() * 1.4,
    rotate: Math.random() * 360,
    color: colors[i % colors.length],
    size: 6 + Math.random() * 6,
    drift: (Math.random() - 0.5) * 200,
  }));

  return (
    <div className="pointer-events-none fixed inset-0 overflow-hidden z-[60]">
      <style>{`
        @keyframes confetti-fall {
          0% { transform: translateY(-10vh) translateX(0) rotate(0deg); opacity: 1; }
          100% { transform: translateY(110vh) translateX(var(--drift)) rotate(720deg); opacity: 0.9; }
        }
      `}</style>
      {pieces.map((p) => (
        <span
          key={p.id}
          style={{
            position: "absolute",
            left: `${p.left}%`,
            top: 0,
            width: p.size,
            height: p.size * 0.4,
            backgroundColor: p.color,
            animation: `confetti-fall ${p.duration}s ease-in ${p.delay}s forwards`,
            "--drift": `${p.drift}px`,
          }}
        />
      ))}
    </div>
  );
}


function BubbleTitle({ darkMode, colorBlind }) {
  const fill = colorBlind ? "#3d8bff" : darkMode ? "#93c5fd" : "#ff8a3d";
  const stroke = darkMode ? "#18181b" : "#1f2937";

  return (
    <h1
      className="select-none text-9xl sm:text-10xl tracking-wide whitespace-nowrap"
      style={{
        fontFamily: "'Baloo 2', system-ui, sans-serif",
        fontWeight: 800,
        color: fill,
        WebkitTextStroke: `1.5px ${stroke}`,
        paintOrder: "stroke fill",
      }}
      aria-label="WORDLE"
    >
      WORDLE
    </h1>
  );
}

function Toggle({ checked, onChange }) {
  return (
    <button
      onClick={onChange}
      className={`w-11 h-6 rounded-full relative transition-colors duration-200 ${checked ? "bg-green-600" : "bg-zinc-400"}`}
    >
      <span
        className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full transition-transform duration-200 ${
          checked ? "translate-x-5" : ""
        }`}
      />
    </button>
  );
}